import{c as t,Q as o,j as n,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Tiered autonomy","description":"One dial that controls how much the agent can do without asking you — from \\"sign everything yourself\\" to \\"a bounded session key acts for you.\\"","frontmatter":{"title":"Tiered autonomy","description":"One dial that controls how much the agent can do without asking you — from \\"sign everything yourself\\" to \\"a bounded session key acts for you.\\""},"headers":[],"relativePath":"policy/tiered-autonomy.md","filePath":"policy/tiered-autonomy.md","lastUpdated":1780196777000}'),a={name:"policy/tiered-autonomy.md"};function i(r,e,d,l,c,h){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="tiered-autonomy" tabindex="-1">Tiered autonomy <a class="header-anchor" href="#tiered-autonomy" aria-label="Permalink to &quot;Tiered autonomy&quot;">​</a></h1><h2 id="the-one-idea" tabindex="-1">The one idea <a class="header-anchor" href="#the-one-idea" aria-label="Permalink to &quot;The one idea&quot;">​</a></h2><p>Tiered autonomy is a single dial with one question on it: <strong>when the agent wants to send a transaction, who signs it?</strong></p><p>At one end, <em>you</em> sign every action with your passkey — the agent can only advise. At the other end, a <strong>session key</strong> with a spending ceiling signs for you, so the agent can act without interrupting you. The tiers in between are the steps along that dial.</p><p>Two things are true at every tier:</p><ul><li><strong>The agent never sees your balances.</strong> Tier choice is about <em>signing</em>, not <em>privacy</em> — your amounts stay encrypted regardless of tier.</li><li><strong>You choose your own tier.</strong> There is no automatic promotion; you pick the tier and confirm the change yourself.</li></ul><div class="warning custom-block"><p class="custom-block-title">Development status — read this first</p><p>Parts of the design on this page are not yet fully wired. The <strong>live, working autonomous path is Scoped autonomy</strong> (a bounded session key + the broker daemon). <strong>Policy-bound</strong>&#39;s encrypted-threshold auto-signing engine is <em>built but disabled in every deployment</em>, the &quot;tier ladder&quot; is <em>not enforced</em> (you choose your tier freely), and on-chain KYC runs in <strong>dev mode</strong>. The exact list is in <a href="#what-s-bypassed-during-development">What&#39;s bypassed during development</a>.</p></div><h2 id="the-tiers-at-a-glance" tabindex="-1">The tiers at a glance <a class="header-anchor" href="#the-tiers-at-a-glance" aria-label="Permalink to &quot;The tiers at a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Who signs each write</th><th>What you do per action</th><th>Status today</th></tr></thead><tbody><tr><td><strong>Advisory</strong></td><td>You — a fresh passkey signature every time</td><td>Approve every action with WebAuthn</td><td>✅ Live</td></tr><tr><td><strong>Confirm per action</strong></td><td>A session key, <em>after</em> you confirm</td><td>Tap &quot;confirm&quot; on each proposed action</td><td>✅ Live</td></tr><tr><td><strong>Policy-bound</strong></td><td><em>Designed:</em> a risk engine, within your caps</td><td>Configure your call-allowlist + spend caps</td><td>⚠️ Partially wired — see below</td></tr><tr><td><strong>Scoped autonomy</strong></td><td>A bounded session key — no prompt</td><td>Set a per-trade cap + expiry <strong>once</strong></td><td>✅ Live — the real autonomous tier</td></tr><tr><td><strong>Paused</strong></td><td>Nobody — all writes blocked</td><td>Nothing (this is the kill-switch)</td><td>✅ Live</td></tr></tbody></table><p>The dial runs <strong>Advisory → Confirm per action → Policy-bound → Scoped autonomy</strong>, with <strong>Paused</strong> reachable from anywhere via <a href="/policy/pause"><code>/pause</code></a>.</p><h2 id="how-you-set-your-tier" tabindex="-1">How you set your tier <a class="header-anchor" href="#how-you-set-your-tier" aria-label="Permalink to &quot;How you set your tier&quot;">​</a></h2><p>Set your tier yourself on the dashboard at <strong><code>/agent/policy/transition</code></strong> (the tier picker), or call <code>muhaven.policy.set_tier</code> (<code>muhaven_set_policy</code> on HavenBot). The change is signed by your passkey.</p><ul><li><strong>Stepping up</strong> (toward more autonomy) needs one confirmation tap — the dashboard issues a short-lived confirm token and you click <strong>Confirm transition</strong>.</li><li><strong>Stepping down</strong> (toward less autonomy) applies immediately, no confirmation needed.</li></ul><div class="tip custom-block"><p class="custom-block-title">Two surfaces, two tier sets</p><p>The <strong>dashboard picker</strong> exposes <strong>Advisory · Confirm per action · Policy-bound · Scoped autonomy</strong>. The <strong>MCP</strong> <code>set_tier</code> tool accepts <strong>advisory · confirm-per-action · policy-bound · paused</strong> — it can&#39;t mint a Scoped session, because Scoped needs an in-browser passkey ceremony to set the cap + expiry. So: arm <strong>Scoped</strong> from the dashboard; manage the lower tiers from anywhere.</p></div><h2 id="advisory-—-the-default" tabindex="-1">Advisory — the default <a class="header-anchor" href="#advisory-—-the-default" aria-label="Permalink to &quot;Advisory — the default&quot;">​</a></h2><blockquote><p>Agent can read your portfolio and propose actions. Every write requires a fresh passkey signature.</p></blockquote><p>The agent reads and advises. When it proposes a write, a ConfirmModal opens with a cleartext preview and you sign with WebAuthn (Touch ID / Windows Hello / hardware key). Nothing moves without that signature.</p><p><strong>When to use:</strong> getting started, after a long break, or any time you want to approve every action yourself. <strong>Trade-off:</strong> highest friction, highest assurance — every action is single-signed by you.</p><h2 id="confirm-per-action-—-the-daily-driver-tier" tabindex="-1">Confirm per action — the daily-driver tier <a class="header-anchor" href="#confirm-per-action-—-the-daily-driver-tier" aria-label="Permalink to &quot;Confirm per action — the daily-driver tier&quot;">​</a></h2><blockquote><p>Agent proposes; a dashboard / Telegram prompt asks you to confirm each write before it submits.</p></blockquote><p>Your MuHaven wallet installs a narrowly-scoped <strong>session key</strong>:</p><ul><li><strong>Target:</strong> only MuHaven contracts.</li><li><strong>Selector allowlist:</strong> only MuHaven SDK functions.</li><li><strong>Value cap</strong> per call, and an optional total cap per session.</li><li><strong>Expiry (TTL):</strong> the session key is valid until it expires (default ~1 hour), then your passkey installs a fresh one.</li></ul><p>While the session key is valid, <em>you still confirm each action</em> (the cleartext preview still appears) — but the <strong>signing</strong> is done by the session key, so you don&#39;t re-prove your identity with the passkey every time.</p><p><strong>When to use:</strong> an active session — a run of HavenBot conversation, a batch of claims. <strong>Trade-off:</strong> medium friction, medium assurance. You confirm <em>what</em>; you don&#39;t re-prove <em>who</em>.</p><h2 id="policy-bound-—-the-automation-tier-design" tabindex="-1">Policy-bound — the automation tier (design) <a class="header-anchor" href="#policy-bound-—-the-automation-tier-design" aria-label="Permalink to &quot;Policy-bound — the automation tier (design)&quot;">​</a></h2><blockquote><p>Agent can write within the call-allowlist + spend caps you configured. Subject to risk-engine pauses.</p></blockquote><p>Policy-bound is the <strong>intended</strong> &quot;set-and-forget within encrypted bounds&quot; tier. As designed, you set encrypted thresholds and a background engine signs actions that stay inside them:</p><ul><li><strong>Max drawdown per position</strong> — e.g. 10% of cost basis.</li><li><strong>Max daily spend</strong> — e.g. $500 per 24-hour window.</li><li><strong>Min yield to accept</strong> — e.g. a 1% APR floor.</li><li><strong>Drift tolerance</strong> — e.g. rebalance when allocation drifts &gt;5% from target.</li></ul><details class="details custom-block"><summary>The design — for the curious</summary><ul><li>Thresholds live encrypted on-chain (<code>RiskParams.sol</code>, <code>euint64</code> slots).</li><li>The check uses a <strong>branchless <code>FHE.select</code></strong> so gas cost is identical whether it passes or fails — no decrypt-timing leakage.</li><li>On a breach: async-decrypt on the Fhenix Threshold Network, then an on-chain <code>settleBreachDecrypt</code> + <code>RiskBreach</code> event on Arbitrum, which pauses the agent and notifies you.</li></ul></details><div class="warning custom-block"><p class="custom-block-title">Not yet wired</p><p>The encrypted-threshold engine above is <strong>not running</strong> in any current deployment (see the next section). Today, selecting Policy-bound gives you an allowlist-scoped tier <strong>without</strong> a live risk engine auto-signing or auto-pausing. If you want autonomous execution today, use <strong>Scoped autonomy</strong>.</p></div><h2 id="scoped-autonomy-—-the-live-autonomous-tier" tabindex="-1">Scoped autonomy — the live autonomous tier <a class="header-anchor" href="#scoped-autonomy-—-the-live-autonomous-tier" aria-label="Permalink to &quot;Scoped autonomy — the live autonomous tier&quot;">​</a></h2><blockquote><p>Autonomous buys &amp; sells within a per-op ceiling, time-bounded by TTL. The agent signs without prompting up to the ceiling.</p></blockquote><p>This is the autonomy that actually runs today. You mint a <strong>Scoped session key</strong> from the dashboard in a passkey ceremony, setting two bounds:</p><ul><li><strong>A per-trade ceiling</strong> — the maximum mhUSDC any single autonomous trade may spend.</li><li><strong>An expiry (TTL)</strong> — how long the session stays armed before it auto-expires.</li></ul><p>A <strong>broker daemon</strong> holds that scoped key and signs the agent&#39;s buys, sells, and claims <strong>without prompting you</strong>, up to the ceiling, until the TTL expires or you revoke it. This is what powers the autonomous reinvest runner and the &quot;active Scoped autonomy session&quot; paths in the MCP tools.</p><p>The standing rails are the real boundary: a purchase/claim-only call policy (with <code>transfer</code> excluded), the per-trade cap, the TTL, and the <a href="/policy/pause"><code>/pause</code></a> kill-switch — all enforced on-chain by the session-key validator.</p><p><strong>When to use:</strong> hands-off auto-claim and reinvest, or letting the agent trade within a budget while you&#39;re away. <strong>Trade-off:</strong> lowest friction. Your safety comes from the cap + TTL + kill-switch, not from a per-action tap.</p><h2 id="paused-—-the-kill-switch-state" tabindex="-1">Paused — the kill-switch state <a class="header-anchor" href="#paused-—-the-kill-switch-state" aria-label="Permalink to &quot;Paused — the kill-switch state&quot;">​</a></h2><p>Anyone, on any surface, can call <code>pause</code> at any time:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Pause my agent.</span></span></code></pre></div><p>On-chain effect: <code>uninstallPlugin(sessionKeyValidator)</code> — a single transaction that removes the session key from your wallet&#39;s permission system (≤ 1 Arb block). Once paused:</p><ul><li>All <code>propose</code>/write tools return <strong><code>423 PAUSED</code></strong>.</li><li>Read tools still work.</li><li><code>pause</code> is idempotent (calling it again is a no-op).</li><li><strong>Resuming requires your passkey</strong> to install a fresh session key — the old one was uninstalled, so it can&#39;t re-authorize itself. On the dashboard this is the <strong>Resume to Advisory</strong> control on the tier picker.</li></ul><p>The kill-switch is <strong>global</strong> — pausing on one surface pauses every surface.</p><p>See <a href="/policy/pause">The /pause kill-switch</a>.</p><h2 id="changing-tier" tabindex="-1">Changing tier <a class="header-anchor" href="#changing-tier" aria-label="Permalink to &quot;Changing tier&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Direction</th><th>What&#39;s required</th></tr></thead><tbody><tr><td>Any non-paused tier → any higher non-paused tier</td><td>One passkey-bound confirm tap (<strong>Confirm transition</strong>)</td></tr><tr><td>Any tier → a lower tier</td><td>Applies immediately, no confirmation</td></tr><tr><td>Arm <strong>Scoped autonomy</strong></td><td>Dashboard passkey ceremony (sets the per-trade cap + TTL)</td></tr><tr><td>Any → <strong>Paused</strong></td><td>Idempotent — no signature needed</td></tr><tr><td><strong>Paused</strong> → any</td><td>Passkey signature (session-key reinstall — <strong>Resume to Advisory</strong>)</td></tr></tbody></table><p>There is <strong>no forced climb</strong>: any non-paused tier can jump directly to any other non-paused tier — you don&#39;t have to step through the tiers in order. Every tier change is recorded as a <code>tier_transition</code> row in your <a href="/policy/audit-log">audit log</a>.</p><h2 id="what-s-bypassed-during-development" tabindex="-1">What&#39;s bypassed during development <a class="header-anchor" href="#what-s-bypassed-during-development" aria-label="Permalink to &quot;What&#39;s bypassed during development&quot;">​</a></h2><p>In the spirit of honest docs, here is exactly where the shipped system is simpler than the design above:</p><ol><li><strong>No automatic tier ladder.</strong> Tier is <strong>purely user-chosen</strong>. There is no promotion by account age, deposit size, or number of confirmed actions — those signals are tracked but gate nothing. The &quot;graduation ladder&quot; (onboarding → returning → power-user) is a design goal, <strong>not enforced</strong> today.</li><li><strong>Policy-bound auto-signing is not running.</strong> The 60-second &quot;policy engine&quot; cron exists in code but is <strong>disabled in every deployment</strong> (<code>AGENT_POLICY_CRON_ENABLED=false</code>, set in no environment). Even when enabled it only <em>sweeps for breaches to pause</em>; it never auto-signs trades. So Policy-bound does <strong>not</strong> currently execute actions for you — <strong>Scoped autonomy</strong> is the live autonomous path.</li><li><strong>Encrypted-threshold gating isn&#39;t driven.</strong> <code>RiskParams.sol</code> is deployed, but no live engine reads it to gate autonomous trades; the default risk adapter is a no-op stub that always reports &quot;no breach.&quot;</li><li><strong>Breach auto-pause is contract-present but undriven.</strong> <code>settleBreachDecrypt</code> / <code>RiskBreach</code> exist on-chain, but nothing runs the cron that would trigger them, so there is no automatic breach → pause today. The manual <a href="/policy/pause"><code>/pause</code></a> kill-switch is fully live.</li><li><strong>KYC runs in dev mode.</strong> <code>MuHavenIdentityRegistry</code> ships with <code>devMode = true</code>, so <code>isVerified</code> returns true for every address — the ERC-3643 whitelist check is bypassed until production KYC partners are wired. (This is compliance, not autonomy, but it&#39;s a development bypass worth knowing.)</li></ol><p>What <em>is</em> fully live and enforced: <strong>Advisory</strong>, <strong>Confirm per action</strong>, <strong>Scoped autonomy</strong> (cap + TTL + on-chain validator), and the <strong>Paused</strong> kill-switch.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/policy/session-keys">Session keys</a> — what a session key actually authorizes.</li><li><a href="/policy/pause">The /pause kill-switch</a> — the kill-switch in depth.</li><li><a href="/policy/audit-log">Audit log</a> — what&#39;s recorded across tier transitions.</li></ul>',53)])])}const g=t(a,[["render",i]]);export{p as __pageData,g as default};
